1	import { describe, it, expect } from "vitest";
2	import { GameOfLife } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should create empty grid", () => {
6	    const gol = new GameOfLife();
7	    expect(gol.getCells()).toEqual([]);
8	  });
9	  it("should add a live cell to the grid", () => {
10	    const gol = new GameOfLife();
11	    gol.addCell(2, 3);
12	    expect(gol.getCells()).toEqual([[2, 3]]);
13	  });
14	  it("should count zero neighbors for isolated cell", () => {
15	    const gol = new GameOfLife();
16	    gol.addCell(5, 5);
17	    expect(gol.countNeighbors(5, 5)).toBe(0);
18	  });
19	  it("should count one neighbor for single adjacent cell", () => {
20	    const gol = new GameOfLife();
21	    gol.addCell(5, 5);
22	    gol.addCell(6, 6);
23	    expect(gol.countNeighbors(5, 5)).toBe(1);
24	  });
25	  it("should count multiple neighbors for adjacent cells", () => {
26	    const gol = new GameOfLife();
27	    gol.addCell(5, 5);
28	    gol.addCell(4, 4);
29	    gol.addCell(4, 5);
30	    gol.addCell(4, 6);
31	    expect(gol.countNeighbors(5, 5)).toBe(3);
32	  });
33	  it("should kill live cell with less than 2 neighbors", () => {
34	    const gol = new GameOfLife();
35	    gol.addCell(5, 5);
36	    gol.addCell(6, 6);
37	    const nextGen = gol.nextGeneration();
38	    expect(nextGen).toEqual([]);
39	  });
40	  it("should keep live cell with 2 neighbors (survival)", () => {
41	    const gol = new GameOfLife();
42	    gol.addCell(5, 5);
43	    gol.addCell(4, 4);
44	    gol.addCell(4, 5);
45	    const nextGen = gol.nextGeneration();
46	    expect(nextGen).toEqual([[4, 4], [4, 5], [5, 4], [5, 5]]);
47	  });
48	  it("should keep live cell with 3 neighbors (survival)", () => {
49	    const gol = new GameOfLife();
50	    gol.addCell(5, 5);
51	    gol.addCell(4, 4);
52	    gol.addCell(4, 5);
53	    gol.addCell(4, 6);
54	    const nextGen = gol.nextGeneration();
55	    expect(nextGen).toEqual([[3, 5], [4, 4], [4, 5], [4, 6], [5, 4], [5, 5], [5, 6]]);
56	  });
57	  it("should kill live cell with more than 3 neighbors", () => {
58	    const gol = new GameOfLife();
59	    gol.addCell(5, 5);
60	    gol.addCell(4, 4);
61	    gol.addCell(4, 5);
62	    gol.addCell(4, 6);
63	    gol.addCell(5, 6);
64	    const nextGen = gol.nextGeneration();
65	    expect(nextGen).toEqual([[3, 5], [4, 4], [4, 6], [5, 4], [5, 6]]);
66	  });
67	  it("should resurrect dead cell with exactly 3 neighbors (reproduction)", () => {
68	    const gol = new GameOfLife();
69	    gol.addCell(4, 4);
70	    gol.addCell(4, 5);
71	    gol.addCell(4, 6);
72	    const nextGen = gol.nextGeneration();
73	    expect(nextGen).toEqual([[3, 5], [4, 5], [5, 5]]);
74	  });
75	  it("should advance one generation", () => {
76	    const gol = new GameOfLife();
77	    // Blinker pattern: vertical line that becomes horizontal
78	    gol.addCell(2, 1);
79	    gol.addCell(2, 2);
80	    gol.addCell(2, 3);
81	    const nextGen = gol.nextGeneration();
82	    // After one generation, blinker should be horizontal
83	    expect(nextGen).toEqual([[1, 2], [2, 2], [3, 2]]);
84	  });
85	  it("should handle negative coordinates", () => {
86	    const gol = new GameOfLife();
87	    gol.addCell(-2, -3);
88	    gol.addCell(-1, -2);
89	    gol.addCell(0, -3);
90	    const nextGen = gol.nextGeneration();
91	    expect(nextGen).toEqual([[-1, -3], [-1, -2], [0, -2]]);
92	  });
93	  it.todo("should keep empty grid empty");
94	});
