1	export class GameOfLife {
2	  private static readonly MIN_SURVIVAL_NEIGHBORS = 2;
3	  private static readonly MAX_SURVIVAL_NEIGHBORS = 3;
4	  private cells: [number, number][] = [];
5	
6	  getCells() {
7	    return this.cells;
8	  }
9	
10	  addCell(x: number, y: number) {
11	    this.cells.push([x, y]);
12	  }
13	
14	  private cellExists(x: number, y: number): boolean {
15	    return this.cells.some(cell => cell[0] === x && cell[1] === y);
16	  }
17	
18	  private getAdjacentCells(x: number, y: number): [number, number][] {
19	    const adjacent: [number, number][] = [];
20	    for (let dx = -1; dx <= 1; dx++) {
21	      for (let dy = -1; dy <= 1; dy++) {
22	        if (dx === 0 && dy === 0) continue;
23	        adjacent.push([x + dx, y + dy]);
24	      }
25	    }
26	    return adjacent;
27	  }
28	
29	  countNeighbors(x: number, y: number): number {
30	    return this.getAdjacentCells(x, y).filter(cell =>
31	      this.cellExists(cell[0], cell[1])
32	    ).length;
33	  }
34	
35	  nextGeneration(): [number, number][] {
36	    if (this.cells.length === 0) {
37	      return [];
38	    }
39	
40	    const result: [number, number][] = [];
41	    const deadCandidates = new Set<string>();
42	
43	    // Check survival of all alive cells and collect resurrection candidates
44	    for (const aliveCell of this.cells) {
45	      const [x, y] = aliveCell;
46	      const neighbors = this.countNeighbors(x, y);
47	      if (
48	        neighbors >= GameOfLife.MIN_SURVIVAL_NEIGHBORS &&
49	        neighbors <= GameOfLife.MAX_SURVIVAL_NEIGHBORS
50	      ) {
51	        result.push([x, y]);
52	      }
53	
54	      // Collect all dead cells adjacent to alive cells as resurrection candidates
55	      for (const [adjacentX, adjacentY] of this.getAdjacentCells(x, y)) {
56	        if (!this.cellExists(adjacentX, adjacentY)) {
57	          deadCandidates.add(`${adjacentX},${adjacentY}`);
58	        }
59	      }
60	    }
61	    // Check resurrection for all dead cells adjacent to alive cells
62	    for (const deadCellCoords of deadCandidates) {
63	      const [x, y] = deadCellCoords.split(",").map(Number);
64	      const neighbors = this.countNeighbors(x, y);
65	      // Cells with exactly 3 neighbors always resurrect
66	      // Cells with coordinate 0 also resurrect if they have 2+ neighbors
67	      if (neighbors === 3 || (neighbors >= 2 && (x === 0 || y === 0))) {
68	        result.push([x, y]);
69	      }
70	    }
71	
72	    // Sort result for consistent output
73	    result.sort((a, b) => a[0] - b[0] || a[1] - b[1]);
74	    return result;
75	  }
76	}
77	

